import React, { useState, useEffect, useRef } from 'react';
import { Mic, MicOff, Send, Pause, Play, Volume2, VolumeX, User, Bot, MessageSquare, FileText, BookOpen, Camera, Eye, Shield, Scale, AlertTriangle, Key } from 'lucide-react';
import { Link, useParams } from 'react-router-dom';

interface Message {
  id: number;
  sender: 'user' | 'ai' | 'system' | 'client' | 'judge' | 'prosecutor';
  content: string;
  timestamp: Date;
}

interface Document {
  _id: string;
  name: string;
  type: 'evidence' | 'witness' | 'legal' | 'financial';
  pages: number;
  description: string;
}

interface EvidenceItem {
  id: string;
  title: string;
  type: 'video' | 'document' | 'photo' | 'audio';
  description: string;
  relevance: 'high' | 'medium' | 'low';
}

const InventoryScenarioSimulation: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 1,
      sender: 'system',
      content: 'Welcome to the CourtCraft courtroom simulation. You are representing the defendant, Rajesh Kumar, in a theft case. The bail hearing is about to begin.',
      timestamp: new Date()
    },
    {
      id: 2,
      sender: 'judge',
      content: 'Good morning. I am Judge Malhotra presiding over this bail application. Please present your case, Counsel.',
      timestamp: new Date()
    }
  ]);
  const [inputMessage, setInputMessage] = useState('');
  const [isRecording, setIsRecording] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [activeTab, setActiveTab] = useState<'chat' | 'documents' | 'evidence' | 'notes' | 'client'>('chat');
  const [documents] = useState<Document[]>([
    {
      _id: '1',
      name: 'CCTV Footage Analysis Report',
      type: 'evidence',
      pages: 3,
      description: 'Analysis of security camera footage from October 15, 2025'
    },
    {
      _id: '2',
      name: 'Digital Inventory Logs',
      type: 'legal',
      pages: 5,
      description: 'Electronic records from Vijay Electronics inventory system'
    },
    {
      _id: '3',
      name: 'Rajesh Kumar Employment Records',
      type: 'legal',
      pages: 2,
      description: '4 years of employment history with Vijay Electronics'
    },
    {
      _id: '4',
      name: 'Financial Records - Ravi Sharma',
      type: 'financial',
      pages: 4,
      description: 'Bank statements showing gambling transactions'
    },
    {
      _id: '5',
      name: 'Service Center Records',
      type: 'legal',
      pages: 1,
      description: 'No record of laptop dispatch to service center'
    }
  ]);
  const [evidenceItems] = useState<EvidenceItem[]>([
    {
      id: '1',
      title: 'CCTV Footage',
      type: 'video',
      description: 'Security camera footage from hallway showing Rajesh exiting storage room',
      relevance: 'high'
    },
    {
      id: '2',
      title: 'Charger Photo',
      type: 'photo',
      description: 'Photo of Rajesh\'s mobile charger showing rectangular hard case',
      relevance: 'high'
    },
    {
      id: '3',
      title: 'Inventory Log Screenshot',
      type: 'photo',
      description: 'Digital log showing laptop marked as dispatched before inventory',
      relevance: 'high'
    }
  ]);
  const [loading, setLoading] = useState(false);
  const [clientInterviewNotes, setClientInterviewNotes] = useState<string>('');
  const [caseStrategy, setCaseStrategy] = useState<string>('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom of messages
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSendMessage = () => {
    if (inputMessage.trim() === '') return;
    
    const newMessage: Message = {
      id: messages.length + 1,
      sender: 'user',
      content: inputMessage,
      timestamp: new Date()
    };
    
    setMessages(prev => [...prev, newMessage]);
    setInputMessage('');
    
    // Simulate AI response after a delay
    setTimeout(() => {
      let aiResponse: Message;
      
      // Simple response logic based on keywords
      if (inputMessage.toLowerCase().includes('bail') || inputMessage.toLowerCase().includes('release')) {
        aiResponse = {
          id: messages.length + 2,
          sender: 'prosecutor',
          content: "Your Honor, the accused was clearly seen taking something from the storage room. The value of the missing laptop is significant. Granting bail would undermine the investigation.",
          timestamp: new Date()
        };
      } else if (inputMessage.toLowerCase().includes('client') || inputMessage.toLowerCase().includes('rajesh')) {
        aiResponse = {
          id: messages.length + 2,
          sender: 'client',
          content: "Sir, I swear on my daughter's life, I didn't take that laptop. I was only putting my charger back in my bag. Please believe me.",
          timestamp: new Date()
        };
      } else if (inputMessage.toLowerCase().includes('evidence') || inputMessage.toLowerCase().includes('proof')) {
        aiResponse = {
          id: messages.length + 2,
          sender: 'ai',
          content: "Counsel, there appears to be a discrepancy in the digital inventory logs. The laptop was marked as dispatched 9:47 AM, before the inventory even began. This suggests internal fraud rather than theft by Rajesh.",
          timestamp: new Date()
        };
      } else {
        // Default response
        aiResponse = {
          id: messages.length + 2,
          sender: 'judge',
          content: "Please continue, Counsel. I'm listening to your arguments.",
          timestamp: new Date()
        };
      }
      
      setMessages(prev => [...prev, aiResponse]);
    }, 2000);
  };

  const toggleRecording = () => {
    setIsRecording(!isRecording);
  };

  const toggleMute = () => {
    setIsMuted(!isMuted);
  };

  const getDocumentIcon = (type: string) => {
    switch (type) {
      case 'evidence': return <FileText className="w-5 h-5 text-red-500" />;
      case 'witness': return <User className="w-5 h-5 text-blue-500" />;
      case 'legal': return <Scale className="w-5 h-5 text-purple-500" />;
      case 'financial': return <FileText className="w-5 h-5 text-green-500" />;
      default: return <FileText className="w-5 h-5 text-gray-500" />;
    }
  };

  const getEvidenceIcon = (type: string) => {
    switch (type) {
      case 'video': return <Camera className="w-5 h-5 text-red-500" />;
      case 'document': return <FileText className="w-5 h-5 text-blue-500" />;
      case 'photo': return <Camera className="w-5 h-5 text-green-500" />;
      case 'audio': return <Mic className="w-5 h-5 text-purple-500" />;
      default: return <FileText className="w-5 h-5 text-gray-500" />;
    }
  };

  const getClientStatement = () => {
    return `Rajesh Kumar's Statement:

"I've worked at Vijay Electronics for four years, and my manager Mr. Desai knows I'm trustworthy. On October 15th, I went to the storage room for our monthly inventory check. I was paired with Prakash, who can vouch for me.

When I bent down to pick up my charger that had fallen, Prakash joked about me being careful. I put it back in my bag and continued working. I never took that laptop!

The CCTV footage must be misinterpreted. My charger has a hard rectangular case that might look like a laptop from that angle. I have no motive to steal - I earn ₹42,000 monthly, have no debts, and was recently considered for a promotion.

I surrendered my passport willingly and offered my father and brother-in-law as sureties. I have a wife and child who depend on me. I would never risk everything for a laptop.

Someone is trying to frame me. Please look at the digital logs - the laptop was marked as dispatched before the inventory even started. That's the real clue!"`;
  };

  const presentBailArguments = () => {
    const bailArgument: Message = {
      id: messages.length + 1,
      sender: 'user',
      content: `Your Honor, I present the following arguments for granting bail to my client, Rajesh Kumar:

1. **No Flight Risk**: 
   - Surrendered passport willingly
   - Strong family ties (wife, child, father, brother-in-law all local)
   - Stable employment for 4 years
   - No prior criminal record

2. **No Tampering with Evidence**:
   - Cooperating fully with investigation
   - Available for questioning anytime
   - Willing to report weekly to police station

3. **Weak Prosecution Case**:
   - CCTV footage is ambiguous - could show charger, not laptop
   - Digital logs show laptop marked as dispatched BEFORE inventory
   - Suggests internal fraud, not theft by Rajesh
   - Only witness (Prakash) supports Rajesh's version

4. **Humanitarian Grounds**:
   - Young daughter who needs father's presence
   - Presumption of innocence is fundamental right
   - Bail is rule, jail is exception under CrPC

We propose bail with personal bond of ₹50,000, two sureties of ₹25,000 each, and weekly police reporting.`,
      timestamp: new Date()
    };
    
    setMessages(prev => [...prev, bailArgument]);
    
    // Simulate judge's response
    setTimeout(() => {
      const judgeResponse: Message = {
        id: messages.length + 2,
        sender: 'judge',
        content: "Thank you, Counsel. I've heard your arguments and reviewed the evidence presented. After careful consideration, I find merit in your client's case. The discrepancies in the digital logs and the ambiguous nature of the CCTV footage raise reasonable doubt. I grant bail to Rajesh Kumar subject to the conditions proposed. Let the record reflect that this is without prejudice to the ongoing investigation.",
        timestamp: new Date()
      };
      
      setMessages(prev => [...prev, judgeResponse]);
      
      // Show completion button after a delay
      setTimeout(() => {
        const completionMessage: Message = {
          id: messages.length + 3,
          sender: 'system',
          content: "Congratulations! You've successfully completed the bail hearing. Click 'Complete Scenario' to review your performance.",
          timestamp: new Date()
        };
        
        setMessages(prev => [...prev, completionMessage]);
      }, 3000);
    }, 3000);
  };

  const completeScenario = () => {
    window.location.href = `/scenario-completion/${id}`;
  };

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <div className="bg-white shadow-sm">
        <div className="container mx-auto px-4 py-4">
          <div className="flex justify-between items-center">
            <div>
              <h1 className="text-2xl font-bold text-gray-900">The Inventory That Changed Everything</h1>
              <p className="text-gray-600">Bail Hearing - Rajesh Kumar vs State</p>
            </div>
            <div className="flex items-center space-x-4">
              <div className="flex items-center bg-amber-100 text-amber-800 px-3 py-1 rounded-full">
                <div className="w-2 h-2 bg-amber-500 rounded-full mr-2 animate-pulse"></div>
                <span className="text-sm font-medium">Live Hearing</span>
              </div>
              <Link to="/scenarios" className="bg-gray-600 text-white px-4 py-2 rounded-lg hover:bg-gray-700 transition duration-300">
                Exit Simulation
              </Link>
            </div>
          </div>
        </div>
      </div>

      <div className="container mx-auto px-4 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Main Courtroom Area */}
          <div className="lg:col-span-2">
            <div className="bg-white rounded-xl shadow-sm overflow-hidden">
              {/* Courtroom Visualization */}
              <div className="bg-gradient-to-b from-amber-800 to-amber-900 h-64 relative">
                <div className="absolute inset-0 flex items-center justify-center">
                  {/* Judge's Bench */}
                  <div className="bg-amber-700 w-64 h-24 rounded-lg flex items-center justify-center shadow-lg">
                    <div className="text-center">
                      <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center mx-auto mb-2">
                        <User className="w-6 h-6 text-amber-800" />
                      </div>
                      <p className="text-white font-medium">Hon. Judge Malhotra</p>
                      <p className="text-amber-200 text-sm">Presiding</p>
                    </div>
                  </div>
                  
                  {/* Defense Table */}
                  <div className="absolute left-8 bottom-8 bg-amber-100 w-48 h-20 rounded-lg flex items-center justify-center shadow">
                    <div className="text-center">
                      <div className="w-8 h-8 bg-indigo-600 rounded-full flex items-center justify-center mx-auto mb-1">
                        <User className="w-4 h-4 text-white" />
                      </div>
                      <p className="text-gray-900 font-medium text-sm">Defense Counsel (You)</p>
                    </div>
                  </div>
                  
                  {/* Prosecution Table */}
                  <div className="absolute right-8 bottom-8 bg-amber-100 w-48 h-20 rounded-lg flex items-center justify-center shadow">
                    <div className="text-center">
                      <div className="w-8 h-8 bg-red-600 rounded-full flex items-center justify-center mx-auto mb-1">
                        <User className="w-4 h-4 text-white" />
                      </div>
                      <p className="text-gray-900 font-medium text-sm">Public Prosecutor</p>
                    </div>
                  </div>
                  
                  {/* Defendant Seat */}
                  <div className="absolute bottom-8 left-1/2 transform -translate-x-1/2 bg-amber-200 w-32 h-16 rounded-lg flex items-center justify-center shadow">
                    <div className="text-center">
                      <div className="w-6 h-6 bg-gray-600 rounded-full flex items-center justify-center mx-auto mb-1">
                        <User className="w-3 h-3 text-white" />
                      </div>
                      <p className="text-gray-900 font-medium text-xs">Rajesh Kumar</p>
                    </div>
                  </div>
                </div>
              </div>
              
              {/* Chat Interface */}
              <div className="p-6">
                {/* Tabs */}
                <div className="flex flex-wrap border-b border-gray-200 mb-6">
                  <button
                    className={`pb-3 px-6 font-medium ${activeTab === 'chat' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-500'}`}
                    onClick={() => setActiveTab('chat')}
                  >
                    <MessageSquare className="w-5 h-5 inline mr-2" />
                    Courtroom
                  </button>
                  <button
                    className={`pb-3 px-6 font-medium ${activeTab === 'client' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-500'}`}
                    onClick={() => setActiveTab('client')}
                  >
                    <User className="w-5 h-5 inline mr-2" />
                    Client Interview
                  </button>
                  <button
                    className={`pb-3 px-6 font-medium ${activeTab === 'documents' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-500'}`}
                    onClick={() => setActiveTab('documents')}
                  >
                    <FileText className="w-5 h-5 inline mr-2" />
                    Documents
                  </button>
                  <button
                    className={`pb-3 px-6 font-medium ${activeTab === 'evidence' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-500'}`}
                    onClick={() => setActiveTab('evidence')}
                  >
                    <Eye className="w-5 h-5 inline mr-2" />
                    Evidence
                  </button>
                  <button
                    className={`pb-3 px-6 font-medium ${activeTab === 'notes' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-500'}`}
                    onClick={() => setActiveTab('notes')}
                  >
                    <BookOpen className="w-5 h-5 inline mr-2" />
                    Strategy
                  </button>
                </div>
                
                {/* Courtroom Tab */}
                {activeTab === 'chat' && (
                  <div className="space-y-6">
                    {/* Messages */}
                    <div className="space-y-4 max-h-96 overflow-y-auto pr-2">
                      {messages.map(message => (
                        <div 
                          key={message.id} 
                          className={`flex ${message.sender === 'user' ? 'justify-end' : 'justify-start'}`}
                        >
                          <div 
                            className={`max-w-xs lg:max-w-md px-4 py-3 rounded-2xl ${
                              message.sender === 'user' 
                                ? 'bg-indigo-600 text-white rounded-br-none' 
                                : message.sender === 'ai'
                                  ? 'bg-gray-100 text-gray-900 rounded-bl-none'
                                  : message.sender === 'system'
                                    ? 'bg-blue-100 text-blue-900 rounded-b-none'
                                    : message.sender === 'client'
                                      ? 'bg-green-100 text-green-900 rounded-bl-none'
                                      : message.sender === 'judge'
                                        ? 'bg-amber-100 text-amber-900 rounded-bl-none'
                                        : message.sender === 'prosecutor'
                                          ? 'bg-red-100 text-red-900 rounded-bl-none'
                                          : 'bg-gray-100 text-gray-900 rounded-bl-none'
                            }`}
                          >
                            <p className="text-sm">{message.content}</p>
                            <p className={`text-xs mt-1 ${
                              message.sender === 'user' 
                                ? 'text-indigo-200' 
                                : message.sender === 'ai'
                                  ? 'text-gray-500'
                                  : message.sender === 'system'
                                    ? 'text-blue-500'
                                    : message.sender === 'client'
                                      ? 'text-green-500'
                                      : message.sender === 'judge'
                                        ? 'text-amber-500'
                                        : message.sender === 'prosecutor'
                                          ? 'text-red-500'
                                          : 'text-gray-500'
                            }`}>
                              {message.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                            </p>
                          </div>
                        </div>
                      ))}
                      <div ref={messagesEndRef} />
                    </div>
                    
                    {/* Input Area */}
                    <div className="flex items-end space-x-3">
                      <div className="flex-1 relative">
                        <textarea
                          value={inputMessage}
                          onChange={(e) => setInputMessage(e.target.value)}
                          onKeyDown={(e) => {
                            if (e.key === 'Enter' && !e.shiftKey) {
                              e.preventDefault();
                              handleSendMessage();
                            }
                          }}
                          placeholder="Present your argument, question witnesses, or respond to the court..."
                          className="w-full px-4 py-3 border border-gray-300 rounded-2xl focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent resize-none"
                          rows={2}
                        />
                      </div>
                      <div className="flex space-x-2">
                        <button
                          onClick={toggleRecording}
                          className={`p-3 rounded-full ${
                            isRecording 
                              ? 'bg-red-100 text-red-600 hover:bg-red-200' 
                              : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                          } transition duration-200`}
                        >
                          {isRecording ? <MicOff className="w-5 h-5" /> : <Mic className="w-5 h-5" />}
                        </button>
                        <button
                          onClick={handleSendMessage}
                          disabled={inputMessage.trim() === ''}
                          className="p-3 bg-indigo-600 text-white rounded-full hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition duration-200"
                        >
                          <Send className="w-5 h-5" />
                        </button>
                      </div>
                    </div>
                    
                    {/* Quick Actions */}
                    <div className="flex flex-wrap gap-2">
                      <button 
                        onClick={presentBailArguments}
                        className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition duration-300 text-sm"
                      >
                        Present Bail Arguments
                      </button>
                      <button className="bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-700 transition duration-300 text-sm">
                        Call Client (Rajesh)
                      </button>
                      <button className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition duration-300 text-sm">
                        Question Witness (Prakash)
                      </button>
                      <button className="bg-amber-600 text-white px-4 py-2 rounded-lg hover:bg-amber-700 transition duration-300 text-sm">
                        Present Evidence
                      </button>
                      <button 
                        onClick={completeScenario}
                        className="bg-purple-600 text-white px-4 py-2 rounded-lg hover:bg-purple-700 transition duration-300 text-sm"
                      >
                        Complete Scenario
                      </button>
                    </div>
                  </div>
                )}
                
                {/* Client Interview Tab */}
                {activeTab === 'client' && (
                  <div className="space-y-6">
                    <div className="bg-gradient-to-r from-indigo-50 to-purple-50 rounded-xl p-6 border border-indigo-100">
                      <h3 className="font-bold text-gray-900 mb-4 flex items-center">
                        <User className="w-5 h-5 mr-2 text-indigo-600" />
                        Client Interview: Rajesh Kumar
                      </h3>
                      <div className="prose max-w-none bg-white p-4 rounded-lg">
                        <pre className="whitespace-pre-wrap text-gray-700 font-sans text-sm">
                          {getClientStatement()}
                        </pre>
                      </div>
                    </div>
                    
                    <div className="bg-white border border-gray-200 rounded-lg p-4">
                      <h4 className="font-bold text-gray-900 mb-3">Key Points from Client Interview</h4>
                      <ul className="space-y-2">
                        <li className="flex items-start">
                          <div className="flex-shrink-0 mt-1">
                            <div className="w-2 h-2 bg-indigo-600 rounded-full"></div>
                          </div>
                          <span className="ml-3 text-gray-700 text-sm">Rajesh has been with Vijay Electronics for 4 years with excellent performance record</span>
                        </li>
                        <li className="flex items-start">
                          <div className="flex-shrink-0 mt-1">
                            <div className="w-2 h-2 bg-indigo-600 rounded-full"></div>
                          </div>
                          <span className="ml-3 text-gray-700 text-sm">No criminal history or financial difficulties</span>
                        </li>
                        <li className="flex items-start">
                          <div className="flex-shrink-0 mt-1">
                            <div className="w-2 h-2 bg-indigo-600 rounded-full"></div>
                          </div>
                          <span className="ml-3 text-gray-700 text-sm">Only witness (Prakash) supports his version of events</span>
                        </li>
                        <li className="flex items-start">
                          <div className="flex-shrink-0 mt-1">
                            <div className="w-2 h-2 bg-indigo-600 rounded-full"></div>
                          </div>
                          <span className="ml-3 text-gray-700 text-sm">Digital logs show laptop was marked as dispatched before inventory began</span>
                        </li>
                        <li className="flex items-start">
                          <div className="flex-shrink-0 mt-1">
                            <div className="w-2 h-2 bg-indigo-600 rounded-full"></div>
                          </div>
                          <span className="ml-3 text-gray-700 text-sm">Surrendered passport and offered two local sureties</span>
                        </li>
                      </ul>
                    </div>
                  </div>
                )}
                
                {/* Documents Tab */}
                {activeTab === 'documents' && (
                  <div className="space-y-4">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      {documents.map(doc => (
                        <div key={doc._id} className="flex items-center p-4 border border-gray-200 rounded-lg hover:bg-gray-50 transition duration-200">
                          <div className="mr-4">
                            {getDocumentIcon(doc.type)}
                          </div>
                          <div className="flex-1">
                            <h4 className="font-medium text-gray-900">{doc.name}</h4>
                            <p className="text-sm text-gray-500">{doc.description}</p>
                            <p className="text-xs text-gray-400">{doc.pages} pages</p>
                          </div>
                          <button className="text-indigo-600 hover:text-indigo-800 font-medium text-sm">
                            Examine
                          </button>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
                
                {/* Evidence Tab */}
                {activeTab === 'evidence' && (
                  <div className="space-y-4">
                    <div className="grid grid-cols-1 gap-4">
                      {evidenceItems.map(item => (
                        <div key={item.id} className="flex items-center p-4 border border-gray-200 rounded-lg hover:bg-gray-50 transition duration-200">
                          <div className="mr-4">
                            {getEvidenceIcon(item.type)}
                          </div>
                          <div className="flex-1">
                            <h4 className="font-medium text-gray-900">{item.title}</h4>
                            <p className="text-sm text-gray-500">{item.description}</p>
                            <div className="flex items-center mt-2">
                              <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${
                                item.relevance === 'high' 
                                  ? 'bg-red-100 text-red-800' 
                                  : item.relevance === 'medium' 
                                    ? 'bg-yellow-100 text-yellow-800' 
                                    : 'bg-green-100 text-green-800'
                              }`}>
                                {item.relevance === 'high' ? 'High Relevance' : item.relevance === 'medium' ? 'Medium Relevance' : 'Low Relevance'}
                              </span>
                            </div>
                          </div>
                          <button className="text-indigo-600 hover:text-indigo-800 font-medium text-sm">
                            Analyze
                          </button>
                        </div>
                      ))}
                    </div>
                    
                    <div className="bg-amber-50 border border-amber-200 rounded-lg p-4">
                      <h4 className="font-bold text-amber-900 mb-2 flex items-center">
                        <AlertTriangle className="w-5 h-5 mr-2" />
                        Key Evidence Insight
                      </h4>
                      <p className="text-amber-800 text-sm">
                        The digital inventory log shows the missing laptop was marked as "dispatched to Service Center" at 9:47 AM, 
                        13 minutes before Rajesh even entered the storage room at 10:00 AM. This suggests internal fraud rather than theft by Rajesh.
                      </p>
                    </div>
                  </div>
                )}
                
                {/* Notes Tab */}
                {activeTab === 'notes' && (
                  <div className="space-y-6">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">Client Interview Notes</label>
                      <textarea
                        value={clientInterviewNotes}
                        onChange={(e) => setClientInterviewNotes(e.target.value)}
                        placeholder="Document key points from your client interview..."
                        className="w-full h-32 px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent resize-none"
                      />
                    </div>
                    
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">Case Strategy & Arguments</label>
                      <textarea
                        value={caseStrategy}
                        onChange={(e) => setCaseStrategy(e.target.value)}
                        placeholder="Develop your legal strategy and key arguments for the bail hearing..."
                        className="w-full h-32 px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent resize-none"
                      />
                    </div>
                    
                    <div className="bg-gradient-to-r from-indigo-50 to-purple-50 rounded-xl p-6 border border-indigo-100">
                      <h3 className="font-bold text-gray-900 mb-4">Suggested Bail Arguments</h3>
                      <div className="prose max-w-none">
                        <ol className="list-decimal pl-5 space-y-2 text-sm text-gray-700">
                          <li><strong>No Flight Risk:</strong> Surrendered passport, local family ties, stable employment, no prior record</li>
                          <li><strong>No Tampering with Evidence:</strong> Cooperating fully, available for questioning</li>
                          <li><strong>Weak Prosecution Case:</strong> Ambiguous CCTV, internal fraud evidence, only witness supports client</li>
                          <li><strong>Humanitarian Grounds:</strong> Young child dependent, presumption of innocence, CrPC provisions</li>
                          <li><strong>Proposed Conditions:</strong> Personal bond, sureties, weekly reporting</li>
                        </ol>
                      </div>
                    </div>
                    
                    <div className="flex justify-end">
                      <button className="bg-indigo-600 text-white px-6 py-2 rounded-lg hover:bg-indigo-700 transition duration-300">
                        Save Strategy
                      </button>
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
          
          {/* Sidebar */}
          <div className="space-y-6">
            {/* Controls */}
            <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-100">
              <h3 className="font-bold text-gray-900 mb-4">Courtroom Controls</h3>
              <div className="space-y-4">
                <button
                  onClick={toggleMute}
                  className="w-full flex items-center justify-center p-3 bg-gray-100 hover:bg-gray-200 rounded-lg transition duration-200"
                >
                  {isMuted ? <VolumeX className="w-5 h-5 mr-2" /> : <Volume2 className="w-5 h-5 mr-2" />}
                  {isMuted ? 'Unmute Audio' : 'Mute Audio'}
                </button>
                <button className="w-full flex items-center justify-center p-3 bg-gray-100 hover:bg-gray-200 rounded-lg transition duration-200">
                  <Pause className="w-5 h-5 mr-2" />
                  Pause Session
                </button>
                <button className="w-full flex items-center justify-center p-3 bg-indigo-600 text-white hover:bg-indigo-700 rounded-lg transition duration-300">
                  <Play className="w-5 h-5 mr-2" />
                  Resume Session
                </button>
              </div>
            </div>
            
            {/* Case Information */}
            <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-100">
              <h3 className="font-bold text-gray-900 mb-4">Case Details</h3>
              <div className="space-y-3">
                <div>
                  <p className="text-sm text-gray-500">Case Type</p>
                  <p className="font-medium">Bail Application - Theft (IPC 379)</p>
                </div>
                <div>
                  <p className="text-sm text-gray-500">Accused</p>
                  <p className="font-medium">Rajesh Kumar, Sales Executive</p>
                </div>
                <div>
                  <p className="text-sm text-gray-500">Value of Alleged Theft</p>
                  <p className="font-medium">₹45,000 (Non-Bailable Offense)</p>
                </div>
                <div>
                  <p className="text-sm text-gray-500">Hearing Date</p>
                  <p className="font-medium">October 17, 2025</p>
                </div>
                <div>
                  <p className="text-sm text-gray-500">Status</p>
                  <span className="inline-block bg-amber-100 text-amber-800 text-xs font-medium px-2.5 py-0.5 rounded-full">
                    In Progress
                  </span>
                </div>
              </div>
            </div>
            
            {/* Key Legal Provisions */}
            <div className="bg-gradient-to-br from-indigo-500 to-purple-600 rounded-xl shadow-sm p-6 text-white">
              <h3 className="font-bold mb-4 flex items-center">
                <Scale className="w-5 h-5 mr-2" />
                Legal Provisions
              </h3>
              <ul className="space-y-2 text-sm">
                <li className="flex items-start">
                  <div className="flex-shrink-0 mt-1">
                    <div className="w-1.5 h-1.5 bg-white rounded-full"></div>
                  </div>
                  <span className="ml-2">IPC 379 - Theft (Punishment)</span>
                </li>
                <li className="flex items-start">
                  <div className="flex-shrink-0 mt-1">
                    <div className="w-1.5 h-1.5 bg-white rounded-full"></div>
                  </div>
                  <span className="ml-2">CrPC 437 - Bail in Non-Bailable Offenses</span>
                </li>
                <li className="flex items-start">
                  <div className="flex-shrink-0 mt-1">
                    <div className="w-1.5 h-1.5 bg-white rounded-full"></div>
                  </div>
                  <span className="ml-2">Article 21 - Right to Life & Liberty</span>
                </li>
                <li className="flex items-start">
                  <div className="flex-shrink-0 mt-1">
                    <div className="w-1.5 h-1.5 bg-white rounded-full"></div>
                  </div>
                  <span className="ml-2">CrPC 438 - Anticipatory Bail</span>
                </li>
              </ul>
            </div>
            
            {/* Timer */}
            <div className="bg-gradient-to-br from-amber-500 to-orange-600 rounded-xl shadow-sm p-6 text-white">
              <h3 className="font-bold mb-2">Hearing Timer</h3>
              <div className="text-3xl font-mono font-bold">12:45</div>
              <p className="text-amber-100 text-sm mt-1">Time elapsed</p>
              <div className="mt-4 w-full bg-white bg-opacity-20 rounded-full h-2">
                <div className="bg-white h-2 rounded-full" style={{ width: '30%' }}></div>
              </div>
              <p className="text-amber-100 text-xs mt-2">30% of allocated time used</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default InventoryScenarioSimulation;
